<?php declare(strict_types=1); namespace App\Http\Controllers\Attendance; use App\Http\Controllers\Controller; use App\Enums\LeaveStatus; use App\Http\Requests\Attendance\LeaveRequestStoreRequest; use App\Models\EmployeeLeaveRequest; use App\Services\Attendance\LeaveRequestService; use Illuminate\Http\RedirectResponse; use Illuminate\Support\Facades\Storage; use Illuminate\View\View;
class EmployeeLeaveController extends Controller{public function index():View{$q=EmployeeLeaveRequest::with('employee')->when(!auth()->user()->can('employee-leaves.view'),fn($q)=>$q->where('employee_id',auth()->user()->employee?->id));return view('attendance.leaves.index',['leaves'=>$q->latest()->paginate(15)]);} public function create():View{return view('attendance.leaves.form');} public function store(LeaveRequestStoreRequest $r,LeaveRequestService $s):RedirectResponse{$s->create($r->validated()+['employee_id'=>auth()->user()->employee->id],$r->file('attachment'));return redirect()->route('employee-leaves.index')->with('status','Pengajuan izin dibuat.');} public function show(EmployeeLeaveRequest $employeeLeave):View{return view('attendance.leaves.show',['leave'=>$employeeLeave->load('employee','approver')]);} public function cancel(EmployeeLeaveRequest $employeeLeave):RedirectResponse{abort_unless($employeeLeave->status===LeaveStatus::Pending,422);$employeeLeave->update(['status'=>LeaveStatus::Cancelled]);activity('attendance')->performedOn($employeeLeave)->causedBy(auth()->user())->event('employee-leave.cancelled')->log('Izin dibatalkan');return back()->with('status','Pengajuan dibatalkan.');} public function approve(EmployeeLeaveRequest $employeeLeave,LeaveRequestService $s):RedirectResponse{$s->approve($employeeLeave);return back()->with('status','Pengajuan disetujui.');} public function reject(EmployeeLeaveRequest $employeeLeave):RedirectResponse{request()->validate(['rejection_reason'=>['required','string']]);app(LeaveRequestService::class)->reject($employeeLeave,request('rejection_reason'));return back()->with('status','Pengajuan ditolak.');} public function download(EmployeeLeaveRequest $employeeLeave){abort_unless($employeeLeave->attachment_path,404);return Storage::disk('private')->download($employeeLeave->attachment_path);}}
